const burn=this.calcMonthlyBurn(),netFlow=rev-cogs-burn;
const runway=netFlow>=0?'Profitable':(Math.floor(((s.cash||0)+(s.personal_cash||0)+(s.available_credit||0))/Math.max(1,-netFlow))+' mo runway');
