const autoCat=(cat,flag)=>{if(!flag)return;const b=this.bestAction(cat);if(b){this.selectedActions[cat]=b;this._paymentMethods[b.id]=this._paymentMethods[b.id]||'cash';this._autoPicked[cat]=b.id;}};
