choices.push('<div class="choice-card fade-in" onclick="Game.resolveTax(\'extend\','+taxOwed+')"><h4>Can\'t pay — request extension</h4><div class="choice-effects">+$'+this.fmt(taxOwed)+' debt, +audit risk (no credit hit)</div></div>');
